        [3, 4, "ARAÇ YIKAMA GİDERİ", 0.2],
        [3, 5, "BEKLEME GİDERİ", 0.2],
        [3, 6, "DEPOLAMA GİDERİ (NAKLİYE BERABERİNDE)", 0.2],
        [3, 8, "FORKLİFT GİDERİ", 0.2],
        [3, 9, "GEMİ GEÇİŞ GİDERİ", 0.2],
        [3, 10, "GÜMRÜK HİZMET GİDERİ", 0.2],
        [3, 11, "HAMALİYE GİDERİ", 0.2],
        [3, 12, "HGS - KÖPRÜ-OTOYOL GİDERİ", 0.2],
        [3, 13, "KM FARKI GİDERİ", 0.2],
        [3, 14, "KONAKLAMA GİDERİ", 0.2],
