        [3, 39, "NAKLİYE HİZMET İADE GELİRİ", 0.2],
        [3, 40, "İÇ NAKLİYE BEDELİ", 0.2],
        [3, 42, "HASAR TAZMİN YANSITMA BEDELİ", 0.2],
        [3, 43, "HASAR TAZMİN İADE BEDELİ", 0.2],
        [3, 44, "TAŞIMA ORGANİZASYON BEDELİ", 0.2],
        [3, 45, "KURYE CEZASI BEDELİ", 0.2],
        [3, 46, "TRAFİK CEZASI BEDELİ", 0.2],
        [3, 47, "EKİPMAN KULLANIM BEDELİ", 0.2],
        [3, 48, "ARAÇ GİYDİRME BEDELİ", 0.2],
        [3, 49, "SÖZLEŞME DAMGA VERGİSİ", 0.2],
        [3, 50, "ELLEÇLEME HİZMETİ YANSITMA BEDELİ", 0.2],
        [3, 52, "DEPO TAŞERON HİZMET GİDERİ", 0.2],
        [3, 53, "DEPO TAŞERON ELLEÇLEME HİZMET GİDERİ", 0.2],
        [3, 54, "HAMMALİYE BEDELİ YANSITMA BEDELİ", 0.2],
        [3, 55, "SATIŞTAN İADE BEDELİ", 0.2],
        [3, 56, "PALETLEME HİZMET BEDELİ", 0.2],
        [3, 57, "PANCAR SÖKÜM BEDELİ", 0.2],
        [3, 58, "OPERASYONEL FİYAT FARKI GELİRİ", 0.2],
        [3, 59, "GEÇ TESLİMAT BEDELİ", 0.2],
        [3, 60, "ARAÇ TEMİN EDİLEMEME BEDELİ", 0.2],
        [3, 61, "ADBLUE GİDERİ", 0.2],
        [3, 62, "HGS HİZMET GİDERİ", 0.2],
        [3, 63, "ÇİFT SÜRÜCÜ BEDELİ", 0.2],
    ];

    const downloadTemplate = () => {
        // 1) ŞABLON sayfası
        const S_HEADERS = [
            "SeferID", "Cari Unvan", "Hesap Adı",
            "Birim Fiyat", "Miktar", "KDV Oranı",
            "Tevkifat Oranı", "Açıklama"
        ];
        const sablonWS = XLSX.utils.aoa_to_sheet([S_HEADERS]);
        // Kolon genişlikleri
        sablonWS["!cols"] = [
            { wch: 10 }, { wch: 28 }, { wch: 26 },
            { wch: 14 }, { wch: 10 }, { wch: 12 },
            { wch: 16 }, { wch: 44 },
        ];

        // 2) DÖKÜMAN sayfası
        const D_HEADERS = ["tip_id", "detay_id", "hizmet_adi", "kdv_oran"];
        const dokumanData = [D_HEADERS, ...DOKUMAN_ROWS];
        const dokumanWS = XLSX.utils.aoa_to_sheet(dokumanData);
        dokumanWS["!cols"] = [{ wch: 8 }, { wch: 10 }, { wch: 46 }, { wch: 10 }];

        // kdv_oran hücrelerine yüzde formatı (0.2 → %20)
        for (let r = 2; r <= dokumanData.length; r++) {
            const addr = "D" + r;
            const cell = dokumanWS[addr];
            if (cell && typeof cell.v === "number") {
                cell.z = "0%";
            }
        }

        // 3) Kitap ve yazma
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, sablonWS, "ŞABLON");
        XLSX.utils.book_append_sheet(wb, dokumanWS, "DÖKÜMAN");
        XLSX.writeFile(wb, "gelir_sablon.xlsx");
    };

    /* ===================== /Excel ===================== */

    const upload = () => {
        if (!file) return;
        // Burada API'ye Excel'i gönderebilirsin:
        // const fd = new FormData(); fd.append("file", file);
        // await fetch("/api/gelir-yukle", { method:"POST", body: fd });
        alert(`Yüklendi: ${file.name}`);
        reset();
    };

    return (
        <div className="ge-page">
            <div className="ge-topbar">
                <div>
                    <h1>Gelir Ekleme</h1>
                    <p className="ge-sub">Excel ile toplu yükleme yap veya dosyayı sürükle-bırak.</p>
                </div>
                <div className="ge-top-actions">
                    <button className="btn ghost" onClick={downloadTemplate}>Şablonu İndir (.xlsx)</button>
                    <button className="btn" onClick={openPicker}>Dosya Seç</button>
                    <input
                        ref={inputRef}
                        type="file"
                        accept={[
                            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                            "application/vnd.ms-excel",
                            ".xlsx",
                            ".xls",
                        ].join(",")}
                        onChange={onFilePicked}
                        hidden
                    />
                </div>
            </div>

            <div
                className={`ge-drop ${isDragging ? "dragging" : ""}`}
                onDragOver={onDragOver}
                onDragLeave={onDragLeave}
                onDrop={onDrop}
                onClick={openPicker}
                role="button"
                tabIndex={0}
            >
                <div className="ge-drop-inner">
                    <div className="ge-icon">⬆️</div>
                    <div className="ge-title">Dosyanı buraya sürükle & bırak</div>
                    <div className="ge-muted">veya <span className="ge-link">bilgisayardan seç</span> (.xlsx, .xls)</div>
                </div>
            </div>

            {file && (
                <div className="ge-file">
                    <div className="ge-file-main">
                        <div className="ge-file-icon">📄</div>
                        <div>
                            <div className="ge-file-name">{file.name}</div>
                            <div className="ge-file-meta">{formatSize(file.size)}</div>
                        </div>
                    </div>
                    <button className="btn ghost danger" onClick={reset}>Kaldır</button>
                </div>
            )}

            {error && <div className="ge-error">{error}</div>}

            <div className="ge-bottombar">
                <div className="ge-bottombar-left">
                    {file ? <span>Yüklemeye hazır: <strong>{file.name}</strong></span> : <span>Henüz dosya seçilmedi</span>}
                </div>
                <div className="ge-bottombar-actions">
                    <button className="btn ghost" onClick={reset} disabled={!file}>Temizle</button>
                    <button className="btn" onClick={upload} disabled={!file}>Yükle</button>
                </div>
            </div>
        </div>
    );
}
